const raw = $input.first().json;
const body = (raw.body && typeof raw.body === 'object') ? raw.body : raw;

const headers = $input.first().json.headers || {};
const apiKey  = headers['x-api-key'] || headers['X-Api-Key'] || '';
const validKey = $env.WEB_API_KEY || 'arvia-dev-key-changeme';
if (apiKey !== validKey) {
  throw new Error('AUTH_FAILED: API key inválida o ausente.');
}

const operation = String(body.operation || 'search');
const VALID_OPS = ['search', 'ai_search', 'publish', 'publish_bulk', 'get_property', 'get_stats'];
if (!VALID_OPS.includes(operation)) {
  throw new Error('OP_INVALID: Operación desconocida: ' + operation);
}

const payload = (body.payload && typeof body.payload === 'object') ? body.payload : {};

return [{ json: { operation, payload, source: 'web', requestedAt: new Date().toISOString() } }];

const p = $input.first().json.payload;

if (!p.title || !p.comuna) throw new Error('VALIDATION: title y comuna son obligatorios.');
const price = parseFloat(p.price);
if (isNaN(price) || price <= 0) throw new Error('VALIDATION: price debe ser mayor a 0.');

return [{ json: {
  title:       String(p.title).slice(0, 255),
  description: String(p.description || '').slice(0, 2000),
  price,
  region:      String(p.region || ''),
  comuna:      String(p.comuna),
  address:     String(p.address || ''),
  bedrooms:    Math.max(0, parseInt(p.bedrooms) || 0),
  bathrooms:   Math.max(0, parseInt(p.bathrooms) || 0),
  sqm:         parseFloat(p.sqm) || 0,
  source_url:  p.source_url ? String(p.source_url) : null,
  source:      'web_dashboard'
} }];

const raw = $input.first().json.payload;
const items = Array.isArray(raw.properties) ? raw.properties
            : Array.isArray(raw) ? raw
            : [];

if (items.length === 0) throw new Error('BULK_EMPTY: El lote está vacío.');
if (items.length > 1000) throw new Error('BULK_TOO_LARGE: Máximo 1000 propiedades por lote.');

const REQUIRED = ['title', 'comuna', 'price'];
const valid = [];
const skipped = [];

for (const [i, p] of items.entries()) {
  const missing = REQUIRED.filter(k => !p[k]);
  if (missing.length) { skipped.push({ row: i+1, reason: 'Faltan: ' + missing.join(', ') }); continue; }
  const price = parseFloat(p.price);
  if (isNaN(price) || price <= 0) { skipped.push({ row: i+1, reason: 'price inválido' }); continue; }
  valid.push({
    title:       String(p.title).slice(0, 255),
    description: String(p.description || '').slice(0, 2000),
    price,
    region:      String(p.region || ''),
    comuna:      String(p.comuna),
    address:     String(p.address || ''),
    bedrooms:    Math.max(0, parseInt(p.bedrooms) || 0),
    bathrooms:   Math.max(0, parseInt(p.bathrooms) || 0),
    sqm:         parseFloat(p.sqm) || 0,
    source_url:  p.source_url ? String(p.source_url) : null,
    source:      'bulk_import'
  });
}

if (valid.length === 0) throw new Error('BULK_ALL_INVALID: Ninguna fila pasó la validación.');

return valid.map(p => ({ json: p }));

