let raw = '';
try { raw = $input.first().json.response || ''; } catch(e) {}

let filters = {};
try {
  const m = raw.match(/\{[^{}]*\}/s);
  if (m) filters = JSON.parse(m[0]);
} catch(e) {}

const result = {
  comuna:           typeof filters.comuna === 'string'    ? filters.comuna.trim() : null,
  bedrooms:         Number.isInteger(filters.bedrooms)    ? Math.max(0, filters.bedrooms) : null,
  bathrooms:        Number.isInteger(filters.bathrooms)   ? Math.max(0, filters.bathrooms) : null,
  max_price:        typeof filters.max_price === 'number' ? filters.max_price : null,
  property_type:    ['departamento','casa'].includes(filters.property_type) ? filters.property_type : null,
  transaction_type: ['venta','arriendo'].includes(filters.transaction_type) ? filters.transaction_type : null
};

return [{ json: { filters: result } }];

const items = $input.all().map(i => i.json);
const single = items.length === 1 ? items[0] : null;
return [{ json: {
  success: true,
  data: items.length === 1 ? single : items,
  count: items.length,
  timestamp: new Date().toISOString()
} }];

const err = $input.first().json.error || {};
const message = typeof err === 'string' ? err : (err.message || 'Error interno del servidor');
const isAuth = message.startsWith('AUTH_FAILED');
const isVal  = message.startsWith('VALIDATION') || message.startsWith('BULK') || message.startsWith('OP_INVALID');
const code   = isAuth ? 403 : isVal ? 400 : 500;

return [{ json: {
  success: false,
  error: message,
  code,
  channel: 'web_api',
  error_message: message,
  error_stack: (err.stack || ''),
  payload: {},
  timestamp: new Date().toISOString()
} }];
